const input = $input.first().json || {};
const clean = (value) => String(value ?? '').trim();
const upper = (value) => clean(value).toUpperCase();
const nowBkk = $now.setZone('Asia/Bangkok');
const explicitMode = upper(input.mode || '');
const allowed = new Set(['DISCUSSION','FINAL','LEVEL_UP_INTERVIEW','FIVE_FAILURES_ANALYSIS','BASE_RULE_REFRAME']);
const triggerReason = upper(input.trigger_reason || input.reason || '');
const rawText = clean(input.raw_text || input.message || '');
const insightPhrases = [/я\s+понял[аи]?/i,/ага/i,/это\s+оно/i,/совпада/i,/инсайт/i,/теперь\s+ясно/i,/точно/i];
let mode = allowed.has(explicitMode) ? explicitMode : '';
if (!mode) {
  if (triggerReason.includes('LEVEL_READY_REACHED')) mode = 'LEVEL_UP_INTERVIEW';
  else if (triggerReason.includes('THERAPIST_REQUIRED') || triggerReason.includes('5_FAIL') || triggerReason.includes('FIVE_FAILURES')) mode = 'FIVE_FAILURES_ANALYSIS';
  else if (input.rule_change_request || input.target_rule_ids) mode = 'BASE_RULE_REFRAME';
  else if (insightPhrases.some((re) => re.test(rawText))) mode = 'FINAL';
  else mode = 'DISCUSSION';
}
const parseArray = (value) => {
  if (Array.isArray(value)) return value.map((v) => clean(v)).filter(Boolean);
  const s = clean(value);
  if (!s) return [];
  try {
    const parsed = JSON.parse(s);
    if (Array.isArray(parsed)) return parsed.map((v) => clean(v)).filter(Boolean);
  } catch (e) {}
  return s.split(',').map((v) => clean(v)).filter(Boolean);
};
return [{ json: {
  mode,
  raw_text: rawText,
  user_id: clean(input.user_id || input.chat_id || '145771888'),
  chat_id: clean(input.chat_id || input.user_id || '145771888'),
  session_id: clean(input.session_id || `${nowBkk.toMillis()}`),
  trigger_reason: clean(input.trigger_reason || input.reason || ''),
  engine_payload: input.engine_payload || {},
  rule_change_request: clean(input.rule_change_request || ''),
  target_rule_ids: parseArray(input.target_rule_ids),
  now_ts: nowBkk.toFormat('yyyy-MM-dd HH:mm:ss'),
  today_date: nowBkk.toFormat('yyyy-MM-dd'),
  timezone: 'Asia/Bangkok'
} }];

const ctx = $input.first().json || {};
const snapshotRaw = $('Read PROFILE_GAME Snapshot').first().json || {};
const beliefsRaw = $('Read Recent BELIEFS').first().json || {};
const rulesRaw = $('Read GAME_RULES').first().json || {};

const clean = (value) => String(value ?? '').trim();
const upper = (value) => clean(value).toUpperCase();
const toNumber = (value) => {
  const raw = clean(value)
    .replace(/฿/g, '')
    .replace(/,/g, '')
    .replace(/[()]/g, (m) => (m === '(' ? '-' : ''))
    .replace(/[^\d.-]/g, '');
  if (!raw) return null;
  const n = Number(raw);
  return Number.isFinite(n) ? n : null;
};
const parseBool = (value) => {
  if (typeof value === 'boolean') return value;
  const s = clean(value).toLowerCase();
  if (['true', 'yes', '1'].includes(s)) return true;
  if (['false', 'no', '0'].includes(s)) return false;
  return null;
};
const rowsFromBatch = (raw) => (((raw.valueRanges || [])[0] || {}).values) || [];
const tableFromRows = (rows, offset = 2) => {
  if (!Array.isArray(rows) || !rows.length) return [];
  const header = rows[0].map(clean);
  return rows.slice(1).filter((row) => row.some((cell) => clean(cell))).map((row, idx) => {
    const obj = { row_number: idx + offset };
    header.forEach((key, i) => {
      obj[key] = row[i] ?? '';
    });
    return obj;
  });
};

const snapshot = {};
for (const row of rowsFromBatch(snapshotRaw)) {
  const leftKey = clean(row[0]);
  const leftVal = clean(row[1]);
  const rightKey = clean(row[2]);
  const rightVal = clean(row[3]);
  if (leftKey) snapshot[leftKey] = leftVal;
  if (rightKey) snapshot[rightKey] = rightVal;
}

const beliefRows = tableFromRows(rowsFromBatch(beliefsRaw), 2);
const ruleRows = tableFromRows(rowsFromBatch(rulesRaw), 2).filter((r) => parseBool(r.ACTIVE) !== false);
const targetRuleIds = Array.isArray(ctx.target_rule_ids) ? ctx.target_rule_ids : [];

const cycleDay = toNumber(snapshot.CYCLE_DAY) ?? toNumber(snapshot.Cycle_Day) ?? toNumber(ctx.engine_payload?.cycle_day) ?? 0;
const hp = toNumber(snapshot.HP_CURRENT) ?? toNumber(ctx.engine_payload?.hp_current) ?? toNumber(ctx.engine_payload?.hp) ?? 0;
const attemptId = clean(snapshot.ACTIVE_ATTEMPT_ID || ctx.engine_payload?.active_attempt_id || '');
const stage = clean(snapshot.PLAYER_STAGE || ctx.engine_payload?.stage || 'EARLY');
const levelName = clean(snapshot.LEVEL_NAME || '');
const activeBossName = clean(snapshot.BOSS_NAME || ctx.engine_payload?.boss_name || '');

let phaseName = '';
if (cycleDay >= 1 && cycleDay <= 5) phaseName = 'Зима';
else if (cycleDay >= 6 && cycleDay <= 12) phaseName = 'Весна';
else if (cycleDay >= 13 && cycleDay <= 15) phaseName = 'Лето';
else if (cycleDay >= 16 && cycleDay <= 28) phaseName = 'Осень';
const phaseDay = cycleDay ? `${cycleDay} — ${phaseName || 'Фаза не определена'}` : '';

const recentBeliefs = beliefRows
  .filter((row) => clean(row.New_Insight || row['New_Insight']))
  .slice(-3)
  .reverse()
  .map((row) => ({
    date: clean(row.Date),
    trigger: clean(row.Trigger),
    old_belief: clean(row.Old_Belief),
    new_insight: clean(row.New_Insight),
    action_step: clean(row.Action_Step),
  }));

const baseRuleIds = new Set([
  'fail_threshold',
  'fail_penalty_xp_gold',
  'stuck_rule',
  'resource_model_xp_gold',
  'resource_model_hp',
  'resource_model_xp_total',
  'energy_rule_2_of_3',
  'hp_lt_50',
  'hp_lt_30',
  'recovery_risk_rule',
  'final_level_up',
]);

const relevantRules = ruleRows
  .filter((row) => {
    const id = clean(row.ID_NAME);
    if (ctx.mode !== 'BASE_RULE_REFRAME') return false;
    if (targetRuleIds.length) return targetRuleIds.includes(id);
    return baseRuleIds.has(id) || upper(row.TYPE).includes('BASE_RULE') || clean(row.NOTES).includes('BASE_RULE');
  })
  .map((row) => ({
    row_number: row.row_number,
    id_name: clean(row.ID_NAME),
    rule_group: clean(row.RULE_GROUP),
    type: clean(row.TYPE),
    rpg_name: clean(row.RPG_NAME),
    track: clean(row.TRACK),
    stage_scope: clean(row.STAGE_SCOPE),
    level_scope: clean(row.LEVEL_SCOPE),
    attempt_scope: clean(row.ATTEMPT_SCOPE),
    value: clean(row.VALUE),
    resource_type: clean(row.RESOURCE_TYPE),
    target_value: clean(row.TARGET_VALUE),
    period: clean(row.PERIOD),
    target_json: clean(row.TARGET_JSON),
    effect: clean(row.EFFECT),
    effect_target: clean(row.EFFECT_TARGET),
    trigger_json: clean(row.TRIGGER_JSON),
    flavor_text: clean(row.FLAVOR_TEXT),
    desc: clean(row.DESC),
    source: clean(row.SOURCE),
    sort_order: clean(row.SORT_ORDER),
    notes: clean(row.NOTES),
  }));

const userPrompt = [
  `MODE: ${ctx.mode}`,
  `RAW_TEXT: ${ctx.raw_text || ''}`,
  `TRIGGER_REASON: ${ctx.trigger_reason || ''}`,
  `PHASE_DAY: ${phaseDay}`,
  `HP: ${hp}`,
  `ATTEMPT_ID: ${attemptId}`,
  `STAGE: ${stage}`,
  `LEVEL_NAME: ${levelName}`,
  `ENGINE_PAYLOAD: ${JSON.stringify(ctx.engine_payload || {})}`,
  `RECENT_BELIEFS: ${JSON.stringify(recentBeliefs)}`,
  `RULE_CHANGE_REQUEST: ${ctx.rule_change_request || ''}`,
  `TARGET_RULE_IDS: ${JSON.stringify(targetRuleIds)}`,
  `RELEVANT_BASE_RULES: ${JSON.stringify(relevantRules)}`,
  'Ответь только JSON-объектом по правилам system prompt.',
].join('\n');

return [
  {
    json: {
      ...ctx,
      cycle_day: cycleDay,
      current_hp: hp,
      phase_day: phaseDay,
      attempt_id: attemptId,
      stage,
      level_name: levelName,
      recent_beliefs: recentBeliefs,
      relevant_rules: relevantRules,
      active_boss_name: activeBossName,
      ai_input: userPrompt,
    },
  },
];

let text = $json.output || $json.text || JSON.stringify($json);
const ctx = $('Build Compact Context').first().json || {};
if (typeof text === 'string') {
  const match = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  if (match) text = match[1];
  text = String(text).replace(/```json/g, '').replace(/```/g, '').trim();
}
const allowed = new Set(['discussion','final','level_up_interview','five_failures_analysis','base_rule_reframe']);
try {
  const parsed = JSON.parse(text);
  parsed.status = String(parsed.status || ctx.mode || 'discussion').toLowerCase();
  if (!allowed.has(parsed.status)) parsed.status = String(ctx.mode || 'DISCUSSION').toLowerCase();
  parsed.trigger = String(parsed.trigger || ctx.raw_text || '').trim();
  parsed.category = String(parsed.category || '').trim();
  parsed.method = String(parsed.method || '').trim();
  parsed.old_belief = String(parsed.old_belief || '').trim();
  parsed.new_insight = String(parsed.new_insight || '').trim();
  parsed.story_text = String(parsed.story_text || '').trim();
  parsed.action_step = String(parsed.action_step || '').trim();
  parsed.summary_for_user = String(parsed.summary_for_user || '').trim();
  parsed.phase_day = String(parsed.phase_day || ctx.phase_day || '').trim();
  parsed.outcome = String(parsed.outcome || '').trim().toUpperCase();
  parsed.reason = String(parsed.reason || '').trim();
  parsed.new_target_json = parsed.new_target_json && typeof parsed.new_target_json === 'object' ? parsed.new_target_json : {};
  parsed.approved_patch = Array.isArray(parsed.approved_patch) ? parsed.approved_patch : [];
  const hp = Number(parsed.hp_cost);
  parsed.hp_cost = Number.isFinite(hp) ? Math.max(0, hp) : (parsed.status === 'final' ? 5 : 0);
  return [{ json: { ...ctx, parsed_response: parsed, ok: true } }];
} catch (e) {
  return [{ json: {
    ...ctx,
    ok: false,
    parsed_response: {
      status: String(ctx.mode || 'DISCUSSION').toLowerCase(),
      trigger: ctx.raw_text || '',
      category: '',
      method: 'Reflection',
      old_belief: '',
      new_insight: '',
      story_text: '',
      action_step: '',
      summary_for_user: 'Произошла техническая ошибка. Попробуй сформулировать это еще раз одним сообщением.',
      phase_day: ctx.phase_day || '',
      outcome: '',
      reason: 'invalid_json',
      new_target_json: {},
      approved_patch: [],
      hp_cost: 0,
    },
    raw_model_output: text,
  } }];
}

const ctx = $input.first().json || {};
const parsed = ctx.parsed_response || {};
const relevantRules = Array.isArray(ctx.relevant_rules) ? ctx.relevant_rules : [];
const clean = (value) => String(value ?? '').trim();
const safeJsonString = (value) => {
  try {
    return JSON.stringify(value || {});
  } catch (e) {
    return '{}';
  }
};
const nowTs = clean(ctx.now_ts);
const today = clean(ctx.today_date);
const attemptId = clean(ctx.attempt_id || ctx.engine_payload?.active_attempt_id || '');
const stage = clean(ctx.stage || ctx.engine_payload?.stage || 'EARLY');
const levelName = clean(ctx.level_name || '1');
const ruleMap = new Map(relevantRules.map((rule) => [clean(rule.id_name), rule]));
const approvedRuleIds = [];
const beliefRows = [];
const gameLogRows = [];
const ruleDeactivateData = [];
const ruleAppendRows = [];

const beliefRow = [
  nowTs,
  clean(parsed.phase_day),
  clean(ctx.raw_text),
  clean(parsed.trigger),
  clean(parsed.category),
  clean(parsed.method),
  clean(parsed.old_belief),
  clean(parsed.new_insight),
  clean(parsed.action_step),
  clean(parsed.hp_cost),
  clean(parsed.story_text),
];

const logRow = ({
  event_type,
  entity_group,
  entity_id = '',
  entity_name = '',
  track = '',
  status = '',
  value = '',
  resource_type = '',
  delta = '',
  period = '',
  date_ref = today,
  stage_at_time = stage,
  level_at_time = levelName,
  attempt_id = attemptId,
  context_json = '',
  comment = '',
}) => [
  nowTs,
  event_type,
  'THERAPIST',
  entity_group,
  entity_id,
  entity_name,
  track,
  status,
  value,
  resource_type,
  delta,
  period,
  date_ref,
  stage_at_time,
  level_at_time,
  attempt_id,
  context_json,
  comment,
];

const appendHpSpent = () => {
  if (Number(parsed.hp_cost || 0) > 0) {
    gameLogRows.push(
      logRow({
        event_type: 'HP_SPENT',
        entity_group: 'THERAPY',
        entity_id: clean(parsed.status),
        entity_name: 'Therapy HP Cost',
        status: 'SPENT',
        value: String(parsed.hp_cost),
        resource_type: 'HP',
        delta: String(-Math.abs(Number(parsed.hp_cost))),
        context_json: safeJsonString({ mode: ctx.mode, trigger_reason: ctx.trigger_reason }),
        comment: clean(parsed.trigger || parsed.summary_for_user),
      }),
    );
  }
};

if (parsed.status === 'discussion') {
  gameLogRows.push(
    logRow({
      event_type: 'THERAPY_DISCUSSION',
      entity_group: 'THERAPY',
      entity_id: 'discussion',
      entity_name: 'Therapy Discussion',
      status: 'DISCUSSION',
      context_json: safeJsonString({ trigger_reason: ctx.trigger_reason, method: parsed.method }),
      comment: clean(parsed.summary_for_user),
    }),
  );
}

if (parsed.status === 'final') {
  beliefRows.push(beliefRow);
  gameLogRows.push(
    logRow({
      event_type: 'BELIEF_RECORDED',
      entity_group: 'BELIEF',
      entity_id: `belief_${Date.now()}`,
      entity_name: clean(parsed.category || 'Belief'),
      status: 'LOGGED',
      value: clean(parsed.new_insight),
      resource_type: 'INSIGHT',
      context_json: safeJsonString({
        method: parsed.method,
        old_belief: parsed.old_belief,
        action_step: parsed.action_step,
      }),
      comment: clean(parsed.summary_for_user),
    }),
  );
  appendHpSpent();
  if (Number(parsed.hp_cost || 0) > 0) {
    gameLogRows.push(
      logRow({
        event_type: 'HP_GAIN',
        entity_group: 'THERAPY',
        entity_id: clean(parsed.status),
        entity_name: 'Therapy HP Recovery',
        status: 'GAINED',
        value: String(parsed.hp_cost),
        resource_type: 'HP',
        delta: String(Math.abs(Number(parsed.hp_cost))),
        context_json: safeJsonString({ mode: ctx.mode, trigger_reason: ctx.trigger_reason }),
        comment: 'HP восстановлен после терапевтической сессии',
      }),
    );
  }
  const activeBossName = clean(ctx.active_boss_name || '');
  if (activeBossName) {
    gameLogRows.push(
      logRow({
        event_type: 'BOSS_DEFEATED',
        entity_group: 'BOSS',
        entity_id: activeBossName.toLowerCase().replace(/\s+/g, '_'),
        entity_name: activeBossName,
        status: 'DEFEATED',
        resource_type: 'XP_Gold',
        context_json: safeJsonString({ defeated_via: 'therapy_session', trigger: parsed.trigger, category: parsed.category }),
        comment: 'Босс побеждён через терапевтическую сессию',
      }),
    );
  }
  gameLogRows.push(
    logRow({
      event_type: 'THERAPY_SESSION_COMPLETED',
      entity_group: 'THERAPY',
      entity_id: 'final',
      entity_name: 'Therapy Session Completed',
      status: 'FINAL',
      context_json: safeJsonString({ trigger: parsed.trigger, category: parsed.category }),
      comment: clean(parsed.summary_for_user),
    }),
  );
}

if (parsed.status === 'level_up_interview') {
  if (parsed.outcome === 'APPROVED') {
    gameLogRows.push(
      logRow({
        event_type: 'LEVEL_UP_APPROVED',
        entity_group: 'LEVEL',
        entity_id: levelName || 'current_level',
        entity_name: levelName || 'Current Level',
        status: 'APPROVED',
        context_json: safeJsonString({ reason: parsed.reason }),
        comment: clean(parsed.summary_for_user),
      }),
    );
  } else if (parsed.outcome === 'HELD') {
    gameLogRows.push(
      logRow({
        event_type: 'LEVEL_UP_HELD',
        entity_group: 'LEVEL',
        entity_id: levelName || 'current_level',
        entity_name: levelName || 'Current Level',
        status: 'HELD',
        context_json: safeJsonString({ reason: parsed.reason }),
        comment: clean(parsed.summary_for_user),
      }),
    );
  } else {
    gameLogRows.push(
      logRow({
        event_type: 'LEVEL_UP_INTERVIEW_STARTED',
        entity_group: 'LEVEL',
        entity_id: levelName || 'current_level',
        entity_name: levelName || 'Current Level',
        status: 'PENDING',
        context_json: safeJsonString({ trigger_reason: ctx.trigger_reason }),
        comment: clean(parsed.summary_for_user),
      }),
    );
  }
  appendHpSpent();
}

if (parsed.status === 'five_failures_analysis') {
  gameLogRows.push(
    logRow({
      event_type: 'FIVE_FAILURES_ANALYZED',
      entity_group: 'THERAPY',
      entity_id: 'five_failures',
      entity_name: 'Five Failures Analysis',
      status: clean(parsed.outcome || 'PENDING'),
      context_json: safeJsonString({ reason: parsed.reason, new_target_json: parsed.new_target_json }),
      comment: clean(parsed.summary_for_user),
    }),
  );
  if (['KEEP', 'ADJUST', 'REPLACE'].includes(parsed.outcome)) {
    gameLogRows.push(
      logRow({
        event_type: 'TARGET_REVIEWED',
        entity_group: 'GOAL',
        entity_id: parsed.outcome.toLowerCase(),
        entity_name: `Target ${parsed.outcome}`,
        status: parsed.outcome,
        context_json: safeJsonString(parsed.new_target_json),
        comment: clean(parsed.reason),
      }),
    );
  }
  appendHpSpent();
}

if (parsed.status === 'base_rule_reframe') {
  gameLogRows.push(
    logRow({
      event_type: 'THERAPY_REFRAME_STARTED',
      entity_group: 'THERAPY',
      entity_id: 'base_rule_reframe',
      entity_name: 'Base Rule Reframe',
      status: clean(parsed.outcome || 'PENDING'),
      context_json: safeJsonString({
        trigger_reason: ctx.trigger_reason,
        rule_change_request: ctx.rule_change_request,
      }),
      comment: clean(parsed.summary_for_user),
    }),
  );

  if (parsed.outcome === 'APPROVED' && Array.isArray(parsed.approved_patch)) {
    for (const patch of parsed.approved_patch) {
      const ruleId = clean(patch.rule_id);
      if (!ruleId) continue;
      const existing = ruleMap.get(ruleId) || {};
      approvedRuleIds.push(ruleId);

      if (existing.row_number) {
        ruleDeactivateData.push({ range: `GAME_RULES!C${existing.row_number}`, values: [[false]] });
      }

      const targetJson =
        patch.target_json && typeof patch.target_json === 'object'
          ? patch.target_json
          : (() => {
              try {
                return JSON.parse(clean(existing.target_json) || '{}');
              } catch (e) {
                return {};
              }
            })();

      ruleAppendRows.push([
        nowTs,
        true,
        clean(existing.rule_group || 'SYSTEM'),
        clean(existing.type || 'BASE_RULE'),
        ruleId,
        clean(existing.rpg_name || ruleId),
        clean(existing.track),
        clean(existing.stage_scope),
        clean(existing.level_scope),
        clean(existing.attempt_scope),
        clean(patch.value ?? existing.value),
        clean(patch.resource_type ?? existing.resource_type),
        clean(patch.target_value ?? existing.target_value),
        clean(patch.period ?? existing.period),
        safeJsonString(targetJson),
        clean(patch.effect ?? existing.effect),
        clean(patch.effect_target ?? existing.effect_target),
        clean(patch.trigger_json ?? existing.trigger_json),
        clean(patch.flavor_text ?? existing.flavor_text),
        clean(patch.desc ?? existing.desc),
        'THERAPIST',
        clean(existing.sort_order),
        clean(patch.notes || 'BASE_RULE|THERAPIST_REFRAME'),
      ]);

      gameLogRows.push(
        logRow({
          event_type: 'RULE_UPDATED',
          entity_group: 'RULE',
          entity_id: ruleId,
          entity_name: ruleId,
          status: 'UPDATED',
          value: clean(patch.value ?? existing.value),
          context_json: safeJsonString({
            target_value: patch.target_value ?? existing.target_value,
            period: patch.period ?? existing.period,
            target_json: targetJson,
          }),
          comment: clean(parsed.reason || parsed.summary_for_user),
        }),
      );
    }

    gameLogRows.push(
      logRow({
        event_type: 'THERAPY_REFRAME_COMPLETED',
        entity_group: 'THERAPY',
        entity_id: 'base_rule_reframe',
        entity_name: 'Base Rule Reframe',
        status: 'APPROVED',
        context_json: safeJsonString({ approved_rule_ids: approvedRuleIds }),
        comment: clean(parsed.summary_for_user),
      }),
    );
  }

  if (clean(parsed.new_insight)) {
    beliefRows.push(beliefRow);
  }
  appendHpSpent();
}

let nextWorkflow = '';
if (parsed.status === 'five_failures_analysis' && ['ADJUST', 'REPLACE'].includes(parsed.outcome)) nextWorkflow = 'GAME_RULES';
if (parsed.status === 'base_rule_reframe' && parsed.outcome !== 'APPROVED') nextWorkflow = 'THERAPIST';

return [
  {
    json: {
      ...ctx,
      ...parsed,
      response_text: clean(parsed.summary_for_user || 'Готово.'),
      belief_rows: beliefRows,
      game_log_rows: gameLogRows,
      rule_deactivate_data: ruleDeactivateData,
      rule_append_rows: ruleAppendRows,
      belief_written: beliefRows.length > 0,
      hp_cost: Number(parsed.hp_cost || 0),
      game_log_rows_count: gameLogRows.length,
      rule_patch_applied: ruleAppendRows.length > 0 || ruleDeactivateData.length > 0,
      approved_rule_ids: approvedRuleIds,
      next_workflow: nextWorkflow,
    },
  },
];
